const usuario = $input.first().json;
const puntosActuales = parseInt(usuario.puntos_lealtad || '0', 10);
const totalPedido = parseFloat($('Construir Pedido').first().json.total_pago) || 0;
// 1 punto por cada $1000 gastado
const puntosGanados = Math.floor(totalPedido / 1000);
return [{ json: {
  telegram_id: $('Construir Pedido').first().json.telegram_id,
  puntos_actuales: puntosActuales,
  puntos_ganados: puntosGanados,
  nuevos_puntos: puntosActuales + puntosGanados
}}];

const pedidos = $input.all().map(p => p.json);
const telegramId = $('Extract Fields').first().json.telegram_id;

if (!pedidos || pedidos.length === 0) {
  return [{ json: { telegram_id: telegramId,
    texto: '📋 *Mis Pedidos*\n\nNo tienes pedidos registrados aún.' }}];
}

// Mostrar los últimos 5 pedidos
const ultimos = pedidos.slice(-5).reverse();
let texto = '📋 *Mis últimos pedidos:*\n\n';
for (const p of ultimos) {
  const emoji = p.estado === 'Entregado' ? '✅'
    : p.estado === 'En camino' ? '🚀'
    : p.estado === 'Preparación' ? '👨‍🍳'
    : '⏳';
  texto += `${emoji} *${p.id_pedido}*\n`;
  texto += `   💰 $${p.total_pago} — ${p.fecha}\n`;
  texto += `   Estado: _${p.estado}_\n\n`;
}

return [{ json: { telegram_id: telegramId, texto }}];

const raw = $input.first().json;

// Detectar si es mensaje de texto o callback de botón
const isCallback = !!raw.callback_query;
const telegramId  = isCallback
  ? raw.callback_query.from.id
  : raw.message?.from?.id;
const nombreUsuario = isCallback
  ? (raw.callback_query.from.first_name || 'Usuario')
  : (raw.message?.from?.first_name || 'Usuario');
const textoMensaje = isCallback
  ? raw.callback_query.data
  : (raw.message?.text || '');
const callbackQueryId = isCallback ? raw.callback_query.id : null;

return [{ json: { telegram_id: String(telegramId), nombre_usuario: nombreUsuario,
                   texto_mensaje: textoMensaje, is_callback: isCallback,
                   callback_query_id: callbackQueryId } }];

const productos = $input.all().map(p => p.json);
const cats = [...new Set(productos.map(p => p.categoria).filter(Boolean))];
const emojis = { bebidas:'☕', comidas:'🍽️', almuerzos:'🍱', snacks:'🍿', postres:'🍰' };
const botones = cats.map(cat => {
  const e = emojis[cat.toLowerCase()] || '🍽️';
  return [{ text: `${e} ${cat}`, callback_data: `cat_${cat.toLowerCase()}` }];
});
botones.push([{ text: '🛒 Mi Carrito', callback_data: 'carrito_ver' }]);
return [{ json: {
  telegram_id: $('Extract Fields').first().json.telegram_id,
  texto: '📋 *Menú DeliveryBot*\n\nElige una categoría:',
  botones
}}];

const msg = $('Extract Fields').first().json.texto_mensaje;
const cat = msg.replace('cat_', '');
const todos = $input.all().map(p => p.json);
const prods = todos.filter(p => p.categoria && p.categoria.toLowerCase() === cat.toLowerCase());
const botones = prods.map(p => ([{
  text: `${p.nombre} — $${parseFloat(p.precio).toFixed(2)}`,
  callback_data: `agregar_${p.id_producto}`
}]));
botones.push([{ text: '🛒 Ver Carrito', callback_data: 'carrito_ver' }]);
botones.push([{ text: '⬅️ Menú Principal', callback_data: 'menu_principal' }]);
return [{ json: {
  telegram_id: $('Extract Fields').first().json.telegram_id,
  texto: `*${cat.toUpperCase()}* 🍽️\n\nElige un producto:`,
  botones,
  categoria: cat
}}];

const telegramId = $('Extract Fields').first().json.telegram_id;
const msg = $('Extract Fields').first().json.texto_mensaje;
const idProducto = msg.replace('agregar_', '');  // string: "P002"

// Leer carrito actual — filtrar entradas corruptas
const sesionRows = $('Leer Sesión Agregar').all();
let carrito = [];
if (sesionRows.length > 0 && sesionRows[0].json.carrito_temporal) {
  try {
    const raw = sesionRows[0].json.carrito_temporal;
    const parsed = (raw && raw !== '[]') ? JSON.parse(raw) : [];
    carrito = parsed.filter(p =>
      p.id_producto !== null && p.id_producto !== undefined &&
      p.nombre && !isNaN(parseFloat(p.precio))
    );
  } catch(e) { carrito = []; }
}

// Producto del MENU
const prodRow = $('Leer Menú Para Producto').all();
const producto = prodRow.length > 0 ? prodRow[0].json : null;

function toNum(val) {
  if (val === null || val === undefined || val === '') return NaN;
  return parseFloat(String(val).replace(/\./g, '').replace(',', '.'));
}

const stockRaw   = producto?.stock  ?? producto?.Stock  ?? '0';
const precioRaw  = producto?.precio ?? producto?.Precio ?? producto?.price ?? '0';
const nombreProd = producto?.nombre ?? producto?.Nombre ?? `Producto ${idProducto}`;
const stockDisponible = parseInt(String(stockRaw), 10) || 0;
const precioNum = toNum(precioRaw);

if (stockDisponible <= 0) {
  return [{ json: { telegram_id: telegramId, sin_stock: true,
                    nombre_producto: nombreProd, carrito } }];
}

if (isNaN(precioNum)) {
  return [{ json: { telegram_id: telegramId, error: true,
                    debug_columnas: Object.keys(producto || {}), carrito } }];
}

// Comparar como string para soportar P001, P002, etc.
const existe = carrito.find(p => String(p.id_producto) === String(idProducto));
if (existe) {
  existe.cantidad += 1;
} else {
  carrito.push({ id_producto: idProducto, nombre: nombreProd,
                 precio: precioNum, cantidad: 1 });
}

const total = carrito.reduce((s, i) => s + (parseFloat(i.precio) * parseInt(i.cantidad, 10)), 0);

return [{ json: {
  telegram_id: telegramId,
  carrito_json: JSON.stringify(carrito),
  total_actual: total.toFixed(2),
  nombre_producto: nombreProd,
  items_count: carrito.reduce((s, i) => s + i.cantidad, 0),
  sin_stock: false,
  error: false
}}];

const sesion = $input.first().json;
let carrito = [];
if (sesion && sesion.carrito_temporal) {
  try {
    const raw = sesion.carrito_temporal;
    carrito = (raw && raw !== '[]') ? JSON.parse(raw) : [];
  } catch(e) { carrito = []; }
}

if (!Array.isArray(carrito)) carrito = [];

let texto = '🛒 *Tu carrito:*\n\n';
let total = 0;

if (carrito.length > 0) {
  for (const item of carrito) {
    const precio = parseFloat(item.precio) || 0;
    const cantidad = parseInt(item.cantidad) || 1;
    const subtotal = precio * cantidad;
    total += subtotal;
    texto += `• *${item.nombre}* x${cantidad} — $${subtotal.toFixed(2)}\n`;
  }
  texto += `\n💰 *Total: $${total.toFixed(2)}*`;
} else {
  texto = '🛒 *Tu carrito está vacío.*\n\nAgrega productos desde el menú.';
}

return [{ json: {
  telegram_id: $('Extract Fields').first().json.telegram_id,
  texto,
  total: total.toFixed(2),
  tiene_items: carrito.length > 0
}}];

const sesion = $('Sesión Confirmar').first().json;
const telegramId = $('Extract Fields').first().json.telegram_id;

let carrito = [];
try {
  const raw = sesion.carrito_temporal;
  carrito = (raw && raw !== '[]') ? JSON.parse(raw) : [];
  carrito = carrito.filter(p => p.id_producto && p.nombre && !isNaN(parseFloat(p.precio)));
} catch(e) { carrito = []; }

if (!Array.isArray(carrito) || carrito.length === 0) {
  return [{ json: { telegram_id: telegramId, carrito_vacio: true,
    mensaje_error: '⚠️ Tu carrito está vacío. Agrega productos primero.' }}];
}

// $input = MENU (Menú Confirmar es el nodo anterior)
const productosMenu = $input.all().map(p => p.json);

let total = 0;
const detalles = [];
const carritoEnriquecido = [];

for (const item of carrito) {
  // Comparar como string para soportar P001, P002, etc.
  const prodMenu = productosMenu.find(p =>
    String(p.id_producto || '').trim() === String(item.id_producto || '').trim()
  );
  const precio = parseFloat(item.precio) || 0;
  const cantidad = parseInt(item.cantidad, 10) || 1;
  const subtotal = precio * cantidad;
  total += subtotal;
  const nombre = item.nombre || prodMenu?.nombre || `Producto ${item.id_producto}`;
  detalles.push(`• ${nombre} x${cantidad} — $${subtotal.toFixed(2)}`);
  const rowIdx = prodMenu ? productosMenu.indexOf(prodMenu) + 2 : null;
  carritoEnriquecido.push({ ...item, precio, row_number_menu: rowIdx });
}

const idPedido = 'PED-' + Date.now().toString().slice(-6);
const ahora = new Date();
const fecha = ahora.toLocaleDateString('es-CO', { timeZone: 'America/Bogota' });
const hora  = ahora.toLocaleTimeString('es-CO', { timeZone: 'America/Bogota' });

return [{ json: {
  telegram_id: telegramId,
  id_pedido: idPedido,
  detalles_pedido: detalles.join('\n'),
  total_pago: total.toFixed(2),
  estado: 'Recibido',
  fecha, hora,
  carrito: carritoEnriquecido,
  carrito_vacio: false
}}];

const pedido = $('Construir Pedido').first().json;
const carrito = Array.isArray(pedido.carrito) ? pedido.carrito : [];

if (carrito.length === 0) {
  return [{ json: { row_number: 2, stock: '0', _skip: true } }];
}

const productosMenu = $('Menú Confirmar').all().map(p => p.json);

const actualizaciones = carrito
  .filter(item => item.row_number_menu !== null && item.row_number_menu !== undefined)
  .map(item => {
    const prodMenu = productosMenu.find(p =>
      String(p.id_producto || '').trim() === String(item.id_producto || '').trim()
    );
    const stockActual = prodMenu ? parseInt(prodMenu.stock, 10) : 0;
    const nuevoStock = Math.max(0, stockActual - parseInt(item.cantidad, 10));
    return { json: { row_number: item.row_number_menu, stock: String(nuevoStock) } };
  });

return actualizaciones.length > 0
  ? actualizaciones
  : [{ json: { row_number: 2, stock: '0', _skip: true } }];

