  botones
}}];

const raw = $input.first().json;
const isCallback = !!raw.callback_query;

const chatId     = isCallback ? String(raw.callback_query.from.id) : String(raw.message?.from?.id || '');
const texto      = isCallback ? raw.callback_query.data : (raw.message?.text || '');
const nombre     = isCallback ? (raw.callback_query.from.first_name || 'Admin')
                               : (raw.message?.from?.first_name || 'Admin');
const callbackId = isCallback ? raw.callback_query.id : null;

// Comandos soportados:
// /estado PED-123456 En camino
// /pedidos               → listar pedidos activos
// /ayuda                 → mostrar ayuda
// callback: estado_PED-123456_Preparación  (desde botones inline)

let comando = 'desconocido';
let idPedido = '';
let nuevoEstado = '';

if (texto === '/start' || texto === '/ayuda') {
  comando = 'ayuda';
} else if (texto === '/pedidos') {
  comando = 'pedidos';
} else if (texto.startsWith('/estado ')) {
  // /estado PED-123456 En camino
  const partes = texto.replace('/estado ', '').split(' ');
  idPedido    = partes[0] || '';
  nuevoEstado = partes.slice(1).join(' ');
  comando     = 'cambiar_estado';
} else if (texto.startsWith('estado_')) {
  // callback_data: estado_PED-123456_En camino
  const sin = texto.replace('estado_', '');
  const idx = sin.indexOf('_');
  idPedido    = sin.substring(0, idx);
  nuevoEstado = sin.substring(idx + 1).replace(/_/g, ' ');
  comando     = 'cambiar_estado';
}

const estadosValidos = ['Recibido', 'Preparacion', 'En camino', 'Entregado'];
const esValido = estadosValidos.includes(nuevoEstado);

return [{ json: {
  chat_id: chatId,
  nombre,
  texto,
  comando,
  id_pedido: idPedido,
  nuevo_estado: nuevoEstado,
  estado_valido: esValido,
  callback_id: callbackId
}}];

const todos = $input.all().map(p => p.json);
const chatId = $('Parsear Comando1').first().json.chat_id;

// Filtrar pedidos no entregados
const activos = todos.filter(p =>
  p.estado && p.estado !== 'Entregado'
);

if (activos.length === 0) {
  return [{ json: {
    chat_id: chatId,
    texto: '✅ No hay pedidos activos en este momento.',
    botones: []
  }}];
}

// Ordenar por hora (más reciente primero)
activos.sort((a, b) => String(b.hora).localeCompare(String(a.hora)));

const emojis = { 'Recibido':'⏳', 'Preparación':'👨‍🍳', 'En camino':'🚀' };
let texto = `📋 *Pedidos Activos (${activos.length}):*\n\n`;

// Botones inline para cambiar estado rápido de cada pedido
const botones = [];

for (const p of activos.slice(0, 10)) {
  const e = emojis[p.estado] || '📦';
  texto += `${e} *${p.id_pedido}*\n`;
  texto += `   👤 Cliente: ${p.id_usuario}\n`;
  texto += `   💰 $${p.total_pago} — 🕐 ${p.hora}\n`;
  texto += `   📦 ${p.estado}\n\n`;

  // Botón para el siguiente estado lógico
  const siguiente = p.estado === 'Recibido'    ? 'Preparación'
                  : p.estado === 'Preparación' ? 'En camino'
                  : p.estado === 'En camino'   ? 'Entregado'
                  : null;

  if (siguiente) {
    const cb = `estado_${p.id_pedido}_${siguiente.replace(/ /g,'_')}`;
    botones.push({ row: { buttons: [{
      text: `▶️ ${p.id_pedido} → ${siguiente}`,
      additionalFields: { callback_data: cb }
    }]}});
  }
}

return [{ json: { chat_id: chatId, texto, botones } }];

const cmd = $('Parsear Comando1').first().json;
const pedido = $('Buscar Pedido1').first().json;
