  const fecha = new Date(`${partes[2]}-${partes[1].padStart(2,'0')}-${partes[0].padStart(2,'0')}`);
  return fecha >= hace30;
});

const totalGeneral = pedidos.reduce((s, p) => s + (parseFloat(p.total_pago) || 0), 0);
const totalMes     = recientes.reduce((s, p) => s + (parseFloat(p.total_pago) || 0), 0);

const conteo = {};
