const productos = $input.all().map(p => p.json);
const chatId    = $('Parsear Entrada Admin1').first().json.chat_id;

if (productos.length === 0) {
  return [{ json: { chat_id: chatId,
    texto: '🍽️ *Gestión de Menú*\n_El menú está vacío._' }}];
}

const cats = {};
for (const p of productos) {
  const cat = p.categoria || 'Sin categoría';
  if (!cats[cat]) cats[cat] = [];
  cats[cat].push(p);
}

let texto = '🍽️ *Menú Completo y Stock*\n';

for (const [cat, prods] of Object.entries(cats)) {
  texto += `*${cat.toUpperCase()}*\n`;
  for (const p of prods) {
    const stock = parseInt(p.stock || 0);
    const semaforo = stock === 0 ? '🔴' : stock < 5 ? '🟡' : '🟢';
    texto += `${semaforo} ${p.nombre} — $${p.precio}\n`;
    texto += `   Stock: ${stock} uds | ID: \`${p.id_producto}\`\n`;
  }
  texto += '\n';
}

texto += '_🔴 Agotado  🟡 Stock bajo (<5)  🟢 Disponible_\n';
texto += '_Para modificar el menú, edita directamente el Google Sheets._';

return [{ json: { chat_id: chatId, texto } }];

const pedidos = $('Leer Pedidos').all().map(p => p.json);
const admins  = $('Leer Admins').all().map(a => a.json);
const hoy     = new Date().toLocaleDateString('es-CO', { timeZone: 'America/Bogota' });

const pedidosHoy = pedidos.filter(p => p.fecha === hoy);

let texto;

if (pedidosHoy.length === 0) {
  texto = `📊 *Reporte del Día — ${hoy}*\n\n_Sin pedidos registrados hoy._`;
} else {
  const totalVendido = pedidosHoy.reduce((s, p) => s + (parseFloat(p.total_pago) || 0), 0);

  const porEstado = {};
  for (const p of pedidosHoy) {
    porEstado[p.estado] = (porEstado[p.estado] || 0) + 1;
  }

  const conteo = {};
  for (const p of pedidosHoy) {
    for (const linea of String(p.detalles_pedido || '').split('\n')) {
      const m = linea.match(/• (.+?) x(\d+)/);
      if (m) conteo[m[1].trim()] = (conteo[m[1].trim()] || 0) + parseInt(m[2]);
    }
  }
  const estrella = Object.entries(conteo).sort((a, b) => b[1] - a[1])[0];

  const horas = {};
  for (const p of pedidosHoy) {
    const h = String(p.hora || '').split(':')[0] + ':00';
    horas[h] = (horas[h] || 0) + 1;
  }
  const horaPico = Object.entries(horas).sort((a, b) => b[1] - a[1])[0];

  const ticketPromedio = totalVendido / pedidosHoy.length;

  const estadoTexto = Object.entries(porEstado)
    .map(([e, c]) => `   • ${e}: ${c}`).join('\n');

  texto =
    `📊 *Reporte del Día — ${hoy}*\n\n` +
    `📦 *Pedidos totales:* ${pedidosHoy.length}\n` +
    `💰 *Total vendido:* $${totalVendido.toLocaleString('es-CO')}\n` +
    `🧾 *Ticket promedio:* $${ticketPromedio.toFixed(0)}\n\n` +
    `📈 *Por estado:*\n${estadoTexto}\n\n` +
    `⭐ *Producto estrella:* ${estrella ? estrella[0] + ' (' + estrella[1] + ' uds)' : 'N/A'}\n` +
    `🕐 *Hora pico:* ${horaPico ? horaPico[0] + ' (' + horaPico[1] + ' pedidos)' : 'N/A'}\n\n` +
    `_Generado a las ${new Date().toLocaleTimeString('es-CO', { timeZone: 'America/Bogota' })}_`;
}

// Generar un item por cada admin
return admins.map(a => ({ json: { chat_id: String(a.telegram_id), texto } }));
